cd "d:/ClaudeWorkspace/08_客户跟进/Okki" && node -e "
const s2 = require('./data/s2_ai_input.json');

// Analyze snippet quality
let withSnippets = 0;
let noSnippets = 0;
let bucket1 = 0;
let bucket2 = 0;

s2.forEach(c => {
  if (c.bucket === 1) bucket1++;
  if (c.bucket === 2) bucket2++;
  const hasValidSnippet = c.snippet && c.snippet.length > 0 && c.snippet.some(s => s.text);
  if (hasValidSnippet) withSnippets++;
  else noSnippets++;
});

console.log('Total:', s2.length);
console.log('Bucket 1 (AI扫一眼):', bucket1);
console.log('Bucket 2 (AI正常读):', bucket2);
console.log('有有效snippet:', withSnippets);
console.log('无有效snippet:', noSnippets);

// Check how many bucket 1 have 0 messages
const bucket1NoMsgs = s2.filter(c => c.bucket === 1 && c.totalMsgs === 0);
console.log('Bucket1 + 0消息:', bucket1NoMsgs.length);

// Show a bucket1 sample with messages but no snippet
const bucket1WithMsgs = s2.filter(c => c.bucket === 1 && c.totalMsgs > 0 && (!c.snippet || c.snippet.length === 0 || !c.snippet.some(s => s.text)));
console.log('Bucket1 + 有消息但无snippet:', bucket1WithMsgs.length);
if (bucket1WithMsgs.length > 0) {
  console.log('Sample:');
  bucket1WithMsgs.slice(0, 5).forEach(c => console.log('  ', c.name, '| msgs:', c.totalMsgs, '| grade:', c.grade));
}
" 2>&1

