    if (grade === 'A') return { grade: 'B', override: 'B' };
    if (grade === 'B') return { grade: 'C', override: 'C' };
  }

  // Adult clothing mismatch — only if we explicitly declined
  if (/(?:ropa de mujer|women.*cloth|adult.*cloth|period pant|seamless pant|femme.*adulte)/i.test(snippetText)) {
    if (/(?:solo.*bebé|solo.*niño|only.*baby|only.*infant|only.*kid|fabricamos.*bebé|manufacture.*baby)/i.test(snippetText)) {
      if (grade !== 'S') return { grade: 'D', override: 'D' };
