// OKKI AI Classification Engine v2
// Reads s2_ai_input.json → lifecycle/priority rules → s3_ai_judgments.json

const fs = require('fs');
const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));

function classify(c) {
  const totalMsgs = c.totalMsgs || 0;
  const customerMsgs = c.customerMsgs || 0;
  const ourMsgs = c.ourMsgs || 0;
  const lastCust = c.lastCustomerMsgDays || 999;
  const dir = c.direction;
  const order = c.order;
  const snippet = c.snippet || [];
  const snippetText = snippet.join(' ');

  let stage = '需求探索';
  let priority = 'idle';
  let reason = '';

  // === CONTENT DETECTION ===
  const hasQuote = /报价|quote|price|\$[0-9]+\b|offer\b|PI\b|proforma|invoice|unit price|成交价|总价|total.{0,20}price|价格.{0,10}\$/i.test(snippetText);
  const hasNegotiation = /negotiate|商量|discount|MOQ|minimum|样品|sample|定制|custom\b|logo|brand|图案|pattern|design/i.test(snippetText);
  const hasPayment = /payment|付款|deposit|定金|paid|收款|confirm.{0,20}order|确认.{0,10}订单/i.test(snippetText);
  const hasShipping = /ship|tracking|物流|express|courier|delivery|收货|forwarder|transitaire|tracking.{0,10}number|运单/i.test(snippetText);
  const hasReceived = /received|收到|arrived|arrivé|reçu|满意|satisf|happy|love.{0,5}it|great.{0,10}product|encantaron/i.test(snippetText);
  const hasComplaint = /problem|issue|wrong.*product|defect|quality.{0,10}issue|complaint|退款|退货|not.{0,10}right/i.test(snippetText);

  // === ORDER-BASED ===
  if (order && order.matched) {
    const st = order.status;
    if (st === '待收款') {
      stage = '待付款';
      if (lastCust <= 7) { priority = 'now'; reason = '有订单待收款，客户' + lastCust + '天前活跃'; }
      else if (lastCust <= 14) { priority = 'soon'; reason = '有订单待收款，静默' + lastCust + '天需催款'; }
      else { priority = 'idle'; reason = '有订单待收款但静默' + lastCust + '天'; }
      return { stage, priority, reason };
    }
    if (st === '待发货') {
      stage = '待发货';
      priority = lastCust <= 14 ? 'soon' : 'idle';
      reason = '订单待发货，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (st === '已发货') {
      stage = '已发货/在途';
      if (lastCust <= 14) { priority = 'now'; reason = '在途需跟踪物流，静默' + lastCust + '天'; }
      else { priority = 'soon'; reason = '在途，静默' + lastCust + '天，需跟踪到港'; }
      return { stage, priority, reason };
    }
    if (st === '交易成功') {
      if (lastCust <= 90) {
        stage = '已签收';
        priority = lastCust <= 30 ? 'soon' : 'idle';
        reason = '订单已完成签收，静默' + lastCust + '天';
      } else {
        stage = '搁置'; priority = 'idle';
        reason = '订单完成超90天自然搁置';
      }
      return { stage, priority, reason };
    }
    if (st === '交易取消') {
      stage = '未成交'; priority = 'idle';
      reason = '订单已取消';
      return { stage, priority, reason };
    }
  }

  // === CONTENT-BASED ===
  // Quote + negotiation still active
  if (hasQuote && hasNegotiation && lastCust <= 14) {
    stage = '谈判中';
    priority = lastCust <= 3 ? 'now' : 'soon';
    reason = '报价+协商进行中，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // Quote sent, waiting
  if (hasQuote) {
    stage = '报价已发';
    if (lastCust <= 3) { priority = 'now'; reason = '刚报价需立即跟进'; }
    else if (lastCust <= 14) { priority = 'soon'; reason = '报价已发' + lastCust + '天，需跟进反馈'; }
    else if (lastCust <= 30) { priority = 'soon'; reason = '报价已发' + lastCust + '天，换策略重联'; }
    else { stage = '搁置'; priority = 'idle'; reason = '报价后静默' + lastCust + '天'; }
    return { stage, priority, reason };
  }

  // Negotiation without explicit quote
  if (hasNegotiation && lastCust <= 14) {
    stage = '谈判中';
    priority = lastCust <= 3 ? 'now' : 'soon';
    reason = '协商中（定制/样品/品牌），静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // Shipping
  if (hasShipping && !hasReceived) {
    stage = '已发货/在途';
    priority = lastCust <= 14 ? 'now' : 'soon';
    reason = '物流跟进中，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // Received
  if ((hasReceived || hasShipping) && lastCust <= 60) {
    stage = '已签收';
    priority = lastCust <= 30 ? 'soon' : 'idle';
    reason = '客户确认收货，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // Complaint
  if (hasComplaint) {
    stage = '售后';
    priority = lastCust <= 1 ? 'now' : 'soon';
    reason = '售后/投诉处理';
    return { stage, priority, reason };
  }

  // Payment
  if (hasPayment) {
    stage = '待付款';
    priority = lastCust <= 7 ? 'now' : (lastCust <= 14 ? 'soon' : 'idle');
    reason = '付款阶段，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // === SILENCE-BASED FALLBACK ===
  // 需求探索 + 不同沉默级别
  if (lastCust <= 3) {
    priority = 'now';
    reason = '需求探索中，客户' + lastCust + '天前活跃需立即回复';
  } else if (lastCust <= 7) {
    priority = 'soon';
    reason = '需求探索中，静默' + lastCust + '天需跟进';
  } else if (lastCust <= 30) {
    // Still in exploration, but cooling
    if (totalMsgs >= 20) {
      priority = 'soon';
      reason = '需求探索（高互动' + totalMsgs + '条），静默' + lastCust + '天需重联';
    } else {
      stage = '搁置';
      priority = 'idle';
      reason = '需求探索短对话，静默' + lastCust + '天进入搁置';
    }
  } else if (lastCust <= 90) {
    stage = '搁置';
    priority = 'idle';
    reason = '静默' + lastCust + '天，需求未推进';
  } else {
    stage = '搁置';
    priority = 'idle';
    reason = '深度静默' + lastCust + '天';
  }

  // Ball-in-our-court override
  if (dir === 'to_us' && lastCust <= 7 && stage !== '搁置' && stage !== '未成交') {
    priority = 'now';
    reason = '球在我方，客户' + lastCust + '天前发消息需回复';
  }

  return { stage, priority, reason };
}

function correctGrade(c, snippetText) {
  let grade = c.grade;
  let override = null;

  // Phantom / non-customer accounts
  if (c.name === 'Leon Scott Kennedy' || c.name === 'Anne Shen') {
    return { grade: 'D', override: 'D' };
  }

  // Personal use → downgrade
  if (/(?:uso personal|personal use|for myself|my baby|mon bébé|primipare)/i.test(snippetText) && c.totalMsgs < 50) {
    if (grade === 'A') return { grade: 'B', override: 'B' };
    if (grade === 'B') return { grade: 'C', override: 'C' };
  }

  // Adult clothing mismatch → D (unless S with big history)
  if (/(?:ropa de mujer|women.*cloth|adult.*cloth|period pant|seamless pant|femme.*adulte|pour femme)/i.test(snippetText)) {
    if (/(?:solo.*bebé|solo.*niño|only.*baby|only.*infant|only.*kid|fabricamos.*bebé|manufacture.*baby|only make.*baby)/i.test(snippetText)) {
      if (grade !== 'S') return { grade: 'D', override: 'D' };
    }
  }

  // Dian Yao type: single message, no follow-up → D
  if (c.totalMsgs <= 2 && c.customerMsgs <= 1 && c.lastCustomerMsgDays > 30) {
    if (grade === 'A' || grade === 'B') return { grade: 'D', override: 'D' };
  }

  return { grade, override };
}

// Process all
const results = [];
const stageDist = {};
const priorityDist = {};
const gradeDist = {};
let gradeCorrections = 0;

s2.forEach(c => {
  const cls = classify(c);
  const snippetText = (c.snippet || []).join(' ');
  const gradeResult = correctGrade(c, snippetText);
  const finalGrade = gradeResult.grade;

  const entry = {
    name: c.name,
    cid: c.cid,
    country: c.country,
    stage: cls.stage,
    grade: finalGrade,
    priority: cls.priority,
    actionHint: cls.reason,
    reason: cls.reason,
    confidence: 'high',
    actionPriority: cls.priority,
    stageLabel: cls.stage,
    actionStatus: cls.priority === 'now' ? '紧急' : (cls.priority === 'soon' ? '尽快处理' : '观察'),
    actionText: cls.reason
  };
  if (gradeResult.override) {
    entry.gradeOverride = gradeResult.override;
    gradeCorrections++;
  }

  results.push(entry);
  stageDist[cls.stage] = (stageDist[cls.stage] || 0) + 1;
  priorityDist[cls.priority] = (priorityDist[cls.priority] || 0) + 1;
  gradeDist[finalGrade] = (gradeDist[finalGrade] || 0) + 1;
});

fs.writeFileSync('./data/s3_ai_judgments.json', JSON.stringify(results, null, 2));

console.log('=== AI Classification v2 ===');
console.log('Total:', results.length);
console.log('Grade corrections:', gradeCorrections);
console.log('Stages:', JSON.stringify(stageDist));
console.log('Stage count:', Object.keys(stageDist).length);
console.log('Priorities:', JSON.stringify(priorityDist));
console.log('Idle %:', (priorityDist.idle / results.length * 100).toFixed(1) + '%');
console.log('Grades:', JSON.stringify(gradeDist));

// Self-checks
const sc = Object.keys(stageDist).length;
const ip = priorityDist.idle / results.length * 100;
console.log(sc >= 6 ? 'PASS: stage count ' + sc : 'FAIL: stage count ' + sc);
console.log(ip <= 60 ? 'PASS: idle ' + ip.toFixed(1) + '%' : 'FAIL: idle ' + ip.toFixed(1) + '%');

// Show NOW customers
console.log('\n=== NOW (' + priorityDist.now + ') ===');
results.filter(r => r.priority === 'now').forEach(r => {
  console.log('  ' + r.name + ' | ' + r.country + ' | ' + r.grade + ' | ' + r.stage);
});

