// OKKI AI Classification Engine
// Reads s2_ai_input.json → applies lifecycle/priority rules → writes s3_ai_judgments.json

const fs = require('fs');
const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));

function classify(c) {
  const totalMsgs = c.totalMsgs || 0;
  const customerMsgs = c.customerMsgs || 0;
  const ourMsgs = c.ourMsgs || 0;
  const lastCust = c.lastCustomerMsgDays || 999;
  const dir = c.direction;
  const order = c.order;
  const snippet = c.snippet || [];
  const snippetText = snippet.join(' ');

  let stage = '需求探索';
  let priority = 'idle';
  let reason = '';

  // --- Order-based stage detection ---
  if (order && order.matched) {
    const status = order.status;
    if (status === '待收款') {
      stage = '待付款';
      priority = lastCust <= 7 ? 'now' : (lastCust <= 14 ? 'soon' : 'idle');
      reason = '有待收款订单，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (status === '待发货') {
      stage = '待发货';
      priority = lastCust <= 7 ? 'soon' : 'idle';
      reason = '订单待发货，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (status === '已发货') {
      stage = '已发货/在途';
      priority = lastCust <= 14 ? 'now' : 'idle';
      reason = '订单已发货在途，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (status === '交易成功') {
      if (lastCust <= 60) {
        stage = '已签收';
        priority = lastCust <= 14 ? 'soon' : 'idle';
        reason = '订单交易成功已签收，静默' + lastCust + '天';
      } else {
        stage = '搁置';
        priority = 'idle';
        reason = '订单已完成，静默' + lastCust + '天自然搁置';
      }
      return { stage, priority, reason };
    }
    if (status === '交易取消') {
      stage = '未成交';
      priority = 'idle';
      reason = '订单已取消';
      return { stage, priority, reason };
    }
  }

  // --- Content-based stage detection ---
  const hasQuote = /报价|quote|price|\$[0-9]+\b|offer\b|PI\b|proforma|invoice|unit price|成交价|总价|total.*price/i.test(snippetText);
  const hasNegotiation = /negotiate|商量|discount|MOQ|minimum|样品|sample|定制|custom\b|logo|brand|图案/i.test(snippetText);
  const hasPayment = /payment|付款|deposit|定金|paid|收款|confirm.*order|确认.*订单/i.test(snippetText);
  const hasShipping = /ship|tracking|物流|express|courier|delivery|收货|forwarder|transitaire|tracking.*number|运单/i.test(snippetText);
  const hasReceived = /received|收到|arrived|arrivé|reçu|满意|satisf|happy|love.*it|great.*product/i.test(snippetText);
  const hasComplaint = /problem|issue|wrong|defect|quality.*issue|complaint|退款|退货|not.*right/i.test(snippetText);

  // Detect if quote was sent
  if (hasQuote && !hasShipping && !hasReceived) {
    if (hasNegotiation && lastCust <= 14) {
      stage = '谈判中';
      priority = lastCust <= 3 ? 'now' : 'soon';
      reason = '谈判中（报价+协商），静默' + lastCust + '天';
    } else {
      stage = '报价已发';
      priority = lastCust <= 3 ? 'now' : (lastCust <= 7 ? 'soon' : 'idle');
      reason = '报价已发，静默' + lastCust + '天';
    }
    return { stage, priority, reason };
  }

  if (hasShipping && !hasReceived) {
    stage = '已发货/在途';
    priority = lastCust <= 14 ? 'now' : 'idle';
    reason = '物流进行中，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  if (hasComplaint) {
    stage = '售后';
    priority = lastCust <= 1 ? 'now' : 'soon';
    reason = '售后/投诉处理';
    return { stage, priority, reason };
  }

  if (hasPayment && !hasShipping) {
    stage = '待付款';
    priority = lastCust <= 7 ? 'now' : (lastCust <= 14 ? 'soon' : 'idle');
    reason = '付款阶段，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // --- Silence-based fallback ---
  if (lastCust > 90) {
    stage = '搁置';
    reason = '深度静默' + lastCust + '天';
    priority = 'idle';
    return { stage, priority, reason };
  }

  if (lastCust > 30 && (stage === '需求探索' || stage === '报价已发')) {
    stage = '搁置';
    reason = '静默' + lastCust + '天，从' + stage + '进入搁置';
    priority = 'idle';
    return { stage, priority, reason };
