// Reads s2_ai_input.json → applies lifecycle/priority rules → writes s3_ai_judgments.json

const fs = require('fs');
const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));

function classify(c) {
  const totalMsgs = c.totalMsgs || 0;
  const customerMsgs = c.customerMsgs || 0;
  const ourMsgs = c.ourMsgs || 0;
  const lastCust = c.lastCustomerMsgDays || 999;
  const dir = c.direction;
  const order = c.order;
  const snippet = c.snippet || [];
  const snippetText = snippet.join(' ');

  let stage = '需求探索';
  let priority = 'idle';
  let reason = '';

  // --- Order-based stage detection ---
  if (order && order.matched) {
    const status = order.status;
    if (status === '待收款') {
      stage = '待付款';
      priority = lastCust <= 7 ? 'now' : (lastCust <= 14 ? 'soon' : 'idle');
      reason = '有待收款订单，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (status === '待发货') {
      stage = '待发货';
      priority = lastCust <= 7 ? 'soon' : 'idle';
      reason = '订单待发货，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (status === '已发货') {
      stage = '已发货/在途';
      priority = lastCust <= 14 ? 'now' : 'idle';
      reason = '订单已发货在途，静默' + lastCust + '天';
      return { stage, priority, reason };
    }
    if (status === '交易成功') {
      if (lastCust <= 60) {
        stage = '已签收';
        priority = lastCust <= 14 ? 'soon' : 'idle';
        reason = '订单交易成功已签收，静默' + lastCust + '天';
      } else {
        stage = '搁置';
        priority = 'idle';
        reason = '订单已完成，静默' + lastCust + '天自然搁置';
      }
      return { stage, priority, reason };
    }
    if (status === '交易取消') {
      stage = '未成交';
      priority = 'idle';
      reason = '订单已取消';
      return { stage, priority, reason };
    }
  }

  // --- Content-based stage detection ---
  const hasQuote = /报价|quote|price|\$[0-9]+\b|offer\b|PI\b|proforma|invoice|unit price|成交价|总价|total.*price/i.test(snippetText);
  const hasNegotiation = /negotiate|商量|discount|MOQ|minimum|样品|sample|定制|custom\b|logo|brand|图案/i.test(snippetText);
  const hasPayment = /payment|付款|deposit|定金|paid|收款|confirm.*order|确认.*订单/i.test(snippetText);
  const hasShipping = /ship|tracking|物流|express|courier|delivery|收货|forwarder|transitaire|tracking.*number|运单/i.test(snippetText);
  const hasReceived = /received|收到|arrived|arrivé|reçu|满意|satisf|happy|love.*it|great.*product/i.test(snippetText);
  const hasComplaint = /problem|issue|wrong|defect|quality.*issue|complaint|退款|退货|not.*right/i.test(snippetText);

  // Detect if quote was sent
  if (hasQuote && !hasShipping && !hasReceived) {
    if (hasNegotiation && lastCust <= 14) {
      stage = '谈判中';
      priority = lastCust <= 3 ? 'now' : 'soon';
      reason = '谈判中（报价+协商），静默' + lastCust + '天';
    } else {
      stage = '报价已发';
      priority = lastCust <= 3 ? 'now' : (lastCust <= 7 ? 'soon' : 'idle');
      reason = '报价已发，静默' + lastCust + '天';
    }
    return { stage, priority, reason };
  }

  if (hasShipping && !hasReceived) {
    stage = '已发货/在途';
    priority = lastCust <= 14 ? 'now' : 'idle';
    reason = '物流进行中，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  if (hasComplaint) {
    stage = '售后';
    priority = lastCust <= 1 ? 'now' : 'soon';
    reason = '售后/投诉处理';
    return { stage, priority, reason };
  }

  if (hasPayment && !hasShipping) {
    stage = '待付款';
    priority = lastCust <= 7 ? 'now' : (lastCust <= 14 ? 'soon' : 'idle');
    reason = '付款阶段，静默' + lastCust + '天';
    return { stage, priority, reason };
  }

  // --- Silence-based fallback ---
  if (lastCust > 90) {
    stage = '搁置';
    reason = '深度静默' + lastCust + '天';
    priority = 'idle';
    return { stage, priority, reason };
  }

  if (lastCust > 30 && (stage === '需求探索' || stage === '报价已发')) {
    stage = '搁置';
    reason = '静默' + lastCust + '天，从' + stage + '进入搁置';
    priority = 'idle';
    return { stage, priority, reason };
  }

  if (lastCust > 14 && totalMsgs < 10 && stage === '需求探索') {
    stage = '搁置';
    reason = '短对话+静默' + lastCust + '天';
    priority = 'idle';
    return { stage, priority, reason };
  }

  // --- Default: active 需求探索 ---
  priority = lastCust <= 1 ? 'now' : (lastCust <= 7 ? 'soon' : 'idle');
  reason = '需求探索中，静默' + lastCust + '天';

  if (dir === 'to_us' && lastCust <= 3) {
    priority = 'now';
    reason = '球在我方，客户' + lastCust + '天前发来消息';
  }

  return { stage, priority, reason };
}

function correctGrade(c, snippetText) {
  let grade = c.grade;
  let override = null;

  // Phantom accounts
  if (c.name === 'Leon Scott Kennedy' || c.name === 'Anne Shen') {
    return { grade: 'D', override: 'D' };
  }

  // Personal use detection
  if (/(?:uso personal|personal use|for myself|my baby|mon bébé|primipare)/i.test(snippetText) && c.totalMsgs < 50) {
    if (grade === 'A') return { grade: 'B', override: 'B' };
    if (grade === 'B') return { grade: 'C', override: 'C' };
  }

  // Adult clothing mismatch — only if we explicitly declined
  if (/(?:ropa de mujer|women.*cloth|adult.*cloth|period pant|seamless pant|femme.*adulte)/i.test(snippetText)) {
    if (/(?:solo.*bebé|solo.*niño|only.*baby|only.*infant|only.*kid|fabricamos.*bebé|manufacture.*baby)/i.test(snippetText)) {
      if (grade !== 'S') return { grade: 'D', override: 'D' };
    }
  }

  return { grade, override };
}

// Process all
const results = [];
const stageDist = {};
const priorityDist = {};
const gradeDist = {};
let gradeCorrections = 0;

s2.forEach(c => {
  const cls = classify(c);
  const snippetText = (c.snippet || []).join(' ');

  const gradeResult = correctGrade(c, snippetText);
  const finalGrade = gradeResult.grade;

  const entry = {
    name: c.name,
    cid: c.cid,
    country: c.country,
    stage: cls.stage,
    grade: finalGrade,
    priority: cls.priority,
    actionHint: cls.reason,
    reason: cls.reason,
    confidence: 'high',
    actionPriority: cls.priority,
    stageLabel: cls.stage,
    actionStatus: cls.priority === 'now' ? '紧急' : (cls.priority === 'soon' ? '尽快处理' : '观察'),
    actionText: cls.reason
  };

  if (gradeResult.override) {
    entry.gradeOverride = gradeResult.override;
    gradeCorrections++;
  }

  results.push(entry);
  stageDist[cls.stage] = (stageDist[cls.stage] || 0) + 1;
  priorityDist[cls.priority] = (priorityDist[cls.priority] || 0) + 1;
  gradeDist[finalGrade] = (gradeDist[finalGrade] || 0) + 1;
});

fs.writeFileSync('./data/s3_ai_judgments.json', JSON.stringify(results, null, 2));

console.log('=== AI Classification Complete ===');
console.log('Total:', results.length);
console.log('Grade corrections:', gradeCorrections);
console.log('');
console.log('Stages:', JSON.stringify(stageDist));
console.log('Stage count:', Object.keys(stageDist).length);
console.log('');
console.log('Priorities:', JSON.stringify(priorityDist));
console.log('Idle %:', (priorityDist.idle / results.length * 100).toFixed(1) + '%');
console.log('');
console.log('Grades:', JSON.stringify(gradeDist));

// Self-check
const stageCount = Object.keys(stageDist).length;
const idlePct = priorityDist.idle / results.length * 100;

if (stageCount < 6) {
  console.log('FAIL: Stage count', stageCount, '< 6 — too coarse');
} else {
  console.log('PASS: Stage count', stageCount, '>= 6');
}

if (idlePct > 60) {
  console.log('FAIL: Idle %', idlePct.toFixed(1), '> 60% — too many idle');
} else {
  console.log('PASS: Idle %', idlePct.toFixed(1), '<= 60%');
}
