  const s = s2Map[c.cid];
  if (!s) return false;
  const d = s.lastCustomerMsgDays;

  // Exclude D grade (already judged as garbage)
  if (c.grade === 'D') return false;

  // Exclude 搁置 with >90d silence (clear terminal)
  if (c.stage === '搁置' && d > 90) return false;

  // Exclude 未成交
  if (c.stage === '未成交') return false;

  // Candidates:
  // 1. 14-90d silence + active stage
  // 2. to_us direction + active stage
  // 3. 搁置 with 14-90d silence (might be misclassified as terminal)
  const activeSilence = d >= 14 && d <= 90 && c.stage !== '搁置';
  const 搁置Silence = c.stage === '搁置' && d >= 14 && d <= 90;
  const ballCourt = s.direction === 'to_us' && d <= 90;

  return activeSilence || 搁置Silence || ballCourt;
});

console.log('AI review candidates:', candidates.length);

// By reason category
const byReason = {};
candidates.forEach(c => {
  const s = s2Map[c.cid];
  const d = s?.lastCustomerMsgDays ?? 0;
