  if (s?.direction === 'to_us') cat = 'to_us';
  else if (c.stage === '搁置' && d >= 14 && d <= 90) cat = '搁置_14-90d';
  else if (d >= 14 && d <= 30) cat = 'active_14-30d';
  else if (d > 30 && d <= 90) cat = 'active_31-90d';
